    let client_a =
        register_and_login(&app.address, "editowner@example.com", "securepassword123").await;
    client_a
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "My private todo")])
        .send()
        .await
        .expect("Failed to add todo");

    // Extract the todo ID from user A's page
